@code {
    private static readonly string[] _stepLabels = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep = 1;
    private bool _isProcessing;
    private bool _submitted;
    private int _applicationId;
    private string _errorMessage = string.Empty;
    private string _emailError = string.Empty;

    // Step 1
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new() };

    // Step 3
    private List<RefModel> _references = new() { new(), new() };

    // Step 4
    private string _coverLetter = string.Empty;

    // Mutable models for form binding
    private record WorkEntryModel
    {
        public string Company { get; init; } = string.Empty;
        public string Title { get; init; } = string.Empty;
        public DateTime StartDate { get; init; } = DateTime.Today;
        public DateTime? EndDate { get; init; }
        public bool IsCurrent { get; init; }
        public string Description { get; init; } = string.Empty;
    }

    private record RefModel
    {
        public string Name { get; init; } = string.Empty;
        public string Relationship { get; init; } = string.Empty;
        public string Email { get; init; } = string.Empty;
        public string Phone { get; init; } = string.Empty;
    }

    private void GoToStep(int step)
    {
        if (step < _currentStep && !_submitted)
        {
            _currentStep = step;
            _errorMessage = string.Empty;
        }
    }

    private void Back()
    {
        _errorMessage = string.Empty;
        _emailError = string.Empty;
        if (_currentStep > 1) _currentStep--;
    }

    // Step 1 validation
    private async Task NextFromStep1()
    {
        _errorMessage = string.Empty;
        _emailError = string.Empty;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
            string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _isProcessing = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email);
            if (!valid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }
            _currentStep = 2;
        }
        finally
        {
            _isProcessing = false;
        }
    }

    // Step 2
    private void UpdateWork(int idx, WorkEntryModel updated) => _workEntries[idx] = updated;
    private void AddWorkEntry() => _workEntries.Add(new());
    private void RemoveWorkEntry(int idx) => _workEntries.RemoveAt(idx);

    private void NextFromStep2()
    {
        _errorMessage = string.Empty;
        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title))
            {
                _errorMessage = "Please fill in the company and job title for every position.";
                return;
            }
        }
        _currentStep = 3;
    }

    // Step 3
    private void UpdateRef(int idx, RefModel updated) => _references[idx] = updated;
    private void AddReference() { if (_references.Count < 3) _references.Add(new()); }
    private void RemoveReference(int idx) => _references.RemoveAt(idx);

    private void NextFromStep3()
    {
        _errorMessage = string.Empty;
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please fill in all fields for every reference.";
                return;
            }
        }
        _currentStep = 4;
    }

    // Step 4
    private void NextFromStep4()
    {
        _errorMessage = string.Empty;
        _currentStep = 5;
    }

    // Submit
    private async Task Submit()
    {
        _errorMessage = string.Empty;
        _isProcessing = true;
        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var work = new WorkHistory(_workEntries
                .Select(e => new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description))
                .ToList());
            var refs = _references
                .Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone))
                .ToList();

            var application = new JobApplication(personal, work, refs, _coverLetter);
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isProcessing = false;
        }
    }
}

