@page "/apply"
@rendermode InteractiveServer
@using sv_a76209a297994553a0b858036f135363.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ── Step Indicator Bar ── *@
    <nav class="d-flex justify-content-between mb-4 position-relative">
        @for (int i = 0; i < _stepLabels.Length; i++)
        {
            var step = i + 1;
            var label = _stepLabels[i];
            var isCurrent = step == _currentStep;
            var isCompleted = step < _currentStep;
            var isFuture = step > _currentStep;

            <div class="text-center flex-fill position-relative">
                <button type="button"
                        class="btn rounded-circle d-inline-flex align-items-center justify-content-center @(isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary")"
                        style="width:36px;height:36px;font-size:.85rem;"
                        disabled="@(isFuture || _submitted)"
                        @onclick="() => GoToStep(step)">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </button>
                <div class="small mt-1 @(isFuture ? "text-muted" : "")">@label</div>
            </div>
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @if (_submitted)
    {
        @* ── Confirmation ── *@
        <div class="text-center py-5">
            <div class="mb-3" style="font-size:3rem;color:green;">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>@_applicationId</strong></p>
            <p class="text-muted">We'll be in touch soon.</p>
        </div>
    }
    else
    {
        @* ── Step 1: Personal Info ── *@
        @if (_currentStep == 1)
        {
            <h4>Personal Information</h4>
            <div class="mb-3">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="_fullName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="_email" />
                @if (!string.IsNullOrEmpty(_emailError))
                {
                    <div class="text-danger small mt-1">@_emailError</div>
                }
            </div>
            <div class="mb-3">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="_phone" />
            </div>
            <div class="mb-3">
                <label class="form-label">Address <span class="text-danger">*</span></label>
                <textarea class="form-control" rows="2" @bind="_address"></textarea>
            </div>
            <div class="d-flex justify-content-end">
                <button class="btn btn-primary" @onclick="NextFromStep1" disabled="@_isProcessing">
                    @if (_isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Next
                </button>
            </div>
        }

        @* ── Step 2: Work History ── *@
        @if (_currentStep == 2)
        {
            <h4>Work History</h4>
            @for (int i = 0; i < _workEntries.Count; i++)
            {
                var idx = i;
                var entry = _workEntries[idx];
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Position @(idx + 1)</h6>
                            @if (_workEntries.Count > 1)
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                            }
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Company <span class="text-danger">*</span></label>
                            <input class="form-control" value="@entry.Company" @onchange="e => UpdateWork(idx, entry with { Company = (string?)e.Value ?? string.Empty })" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Job Title <span class="text-danger">*</span></label>
                            <input class="form-control" value="@entry.Title" @onchange="e => UpdateWork(idx, entry with { Title = (string?)e.Value ?? string.Empty })" />
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" value="@entry.StartDate.ToString("yyyy-MM-dd")" @onchange="e => UpdateWork(idx, entry with { StartDate = DateTime.Parse((string?)e.Value ?? string.Empty) })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" disabled="@entry.IsCurrent"
                                       value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                                       @onchange="e => UpdateWork(idx, entry with { EndDate = string.IsNullOrEmpty((string?)e.Value) ? null : DateTime.Parse((string)e.Value) })" />
                                <div class="form-check mt-1">
                                    <input class="form-check-input" type="checkbox" checked="@entry.IsCurrent"
                                           @onchange="e => UpdateWork(idx, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                                    <label class="form-check-label">Currently working here</label>
                                </div>
                            </div>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Description</label>
                            <textarea class="form-control" rows="2" value="@entry.Description" @onchange="e => UpdateWork(idx, entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
                        </div>
                    </div>
                </div>
            }
            <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromStep2">Next</button>
            </div>
        }

        @* ── Step 3: References ── *@
        @if (_currentStep == 3)
        {
            <h4>References</h4>
            @for (int i = 0; i < _references.Count; i++)
            {
                var idx = i;
                var r = _references[idx];
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Reference @(idx + 1)</h6>
                            @if (_references.Count > 1)
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(idx)">Remove</button>
                            }
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" value="@r.Name" @onchange="e => UpdateRef(idx, r with { Name = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" value="@r.Relationship" @onchange="e => UpdateRef(idx, r with { Relationship = (string?)e.Value ?? string.Empty })" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" value="@r.Email" @onchange="e => UpdateRef(idx, r with { Email = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" value="@r.Phone" @onchange="e => UpdateRef(idx, r with { Phone = (string?)e.Value ?? string.Empty })" />
                            </div>
                        </div>
                    </div>
                </div>
            }
            @if (_references.Count < 3)
            {
                <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">+ Add Reference</button>
            }
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromStep3">Next</button>
            </div>
        }

        @* ── Step 4: Cover Letter ── *@
        @if (_currentStep == 4)
        {
            <h4>Cover Letter</h4>
            <div class="mb-2">
                <textarea class="form-control" rows="10" maxlength="2000" @bind="_coverLetter"></textarea>
            </div>
            <div class="text-muted small mb-3">@_coverLetter.Length / 2000 characters</div>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromStep4">Next</button>
            </div>
        }

        @* ── Step 5: Review & Submit ── *@
        @if (_currentStep == 5)
        {
            <h4>Review &amp; Submit</h4>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Personal Information</strong>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(1)'>Edit</button>
                </div>
                <div class="card-body">
                    <p class="mb-1"><strong>Name:</strong> @_fullName</p>
                    <p class="mb-1"><strong>Email:</strong> @_email</p>
                    <p class="mb-1"><strong>Phone:</strong> @_phone</p>
                    <p class="mb-0"><strong>Address:</strong> @_address</p>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Work History</strong>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(2)'>Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var entry in _workEntries)
                    {
                        <div class="mb-2 pb-2 border-bottom">
                            <p class="mb-1"><strong>@entry.Title</strong> at @entry.Company</p>
                            <p class="mb-1 text-muted small">
                                @entry.StartDate.ToString("MMM yyyy") –
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                            </p>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mb-0 small">@entry.Description</p>
                            }
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>References</strong>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(3)'>Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var r in _references)
                    {
                        <div class="mb-2 pb-2 border-bottom">
                            <p class="mb-1"><strong>@r.Name</strong> (@r.Relationship)</p>
                            <p class="mb-0 small">@r.Email &middot; @r.Phone</p>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Cover Letter</strong>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(4)'>Edit</button>
                </div>
                <div class="card-body">
                    <p style="white-space:pre-wrap;">@_coverLetter</p>
                </div>
            </div>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-success" @onclick="Submit" disabled="@_isProcessing">
                    @if (_isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Submit Application
                </button>
            </div>
        }
    }
</div>

@code {
    private static readonly string[] _stepLabels = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep = 1;
    private bool _isProcessing;
    private bool _submitted;
    private int _applicationId;
    private string _errorMessage = string.Empty;
    private string _emailError = string.Empty;

    // Step 1
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new() };

    // Step 3
    private List<RefModel> _references = new() { new(), new() };

    // Step 4
    private string _coverLetter = string.Empty;

    // Mutable models for form binding
    private record WorkEntryModel
    {
        public string Company { get; init; } = string.Empty;
        public string Title { get; init; } = string.Empty;
        public DateTime StartDate { get; init; } = DateTime.Today;
        public DateTime? EndDate { get; init; }
        public bool IsCurrent { get; init; }
        public string Description { get; init; } = string.Empty;
    }

    private record RefModel
    {
        public string Name { get; init; } = string.Empty;
        public string Relationship { get; init; } = string.Empty;
        public string Email { get; init; } = string.Empty;
        public string Phone { get; init; } = string.Empty;
    }

    private void GoToStep(int step)
    {
        if (step < _currentStep && !_submitted)
        {
            _currentStep = step;
            _errorMessage = string.Empty;
        }
    }

    private void Back()
    {
        _errorMessage = string.Empty;
        _emailError = string.Empty;
        if (_currentStep > 1) _currentStep--;
    }

    // Step 1 validation
    private async Task NextFromStep1()
    {
        _errorMessage = string.Empty;
        _emailError = string.Empty;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
            string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _isProcessing = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email);
            if (!valid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }
            _currentStep = 2;
        }
        finally
        {
            _isProcessing = false;
        }
    }

    // Step 2
    private void UpdateWork(int idx, WorkEntryModel updated) => _workEntries[idx] = updated;
    private void AddWorkEntry() => _workEntries.Add(new());
    private void RemoveWorkEntry(int idx) => _workEntries.RemoveAt(idx);

    private void NextFromStep2()
    {
        _errorMessage = string.Empty;
        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title))
            {
                _errorMessage = "Please fill in the company and job title for every position.";
                return;
            }
        }
        _currentStep = 3;
    }

    // Step 3
    private void UpdateRef(int idx, RefModel updated) => _references[idx] = updated;
    private void AddReference() { if (_references.Count < 3) _references.Add(new()); }
    private void RemoveReference(int idx) => _references.RemoveAt(idx);

    private void NextFromStep3()
    {
        _errorMessage = string.Empty;
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please fill in all fields for every reference.";
                return;
            }
        }
        _currentStep = 4;
    }

    // Step 4
    private void NextFromStep4()
    {
        _errorMessage = string.Empty;
        _currentStep = 5;
    }

    // Submit
    private async Task Submit()
    {
        _errorMessage = string.Empty;
        _isProcessing = true;
        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var work = new WorkHistory(_workEntries
                .Select(e => new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description))
                .ToList());
            var refs = _references
                .Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone))
                .ToList();

            var application = new JobApplication(personal, work, refs, _coverLetter);
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isProcessing = false;
        }
    }
}

